"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";

const API = "http://127.0.0.1:8000/api";

const OPTIONS = [
  { key: "weight", label: "Weight Management" },
  { key: "fitness", label: "Fitness & Activity" },
  { key: "nutrition", label: "Nutrition" },
  { key: "sleep", label: "Sleep Improvement" },
  { key: "stress", label: "Stress & Mental Wellness" },
];

export default function GetStartedPage() {
  const router = useRouter();
  const [selected, setSelected] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  // 🔐 Auth guard
  useEffect(() => {
    if (!localStorage.getItem("access")) {
      router.push("/signup");
    }
  }, []);

  const toggle = (key: string) => {
    setSelected((prev) =>
      prev.includes(key)
        ? prev.filter((i) => i !== key)
        : [...prev, key]
    );
  };

  const saveAndContinue = async () => {
    if (selected.length === 0) {
      alert("Please select at least one focus area.");
      return;
    }

    setLoading(true);

    await fetch(`${API}/profile/`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("access")}`,
      },
      body: JSON.stringify({
        wellness_interests: selected,
      }),
    });

    setLoading(false);
    router.push("/profile");
  };

  return (
    <main style={{ padding: 40, maxWidth: 900, margin: "auto" }}>
      <h1 style={{ fontSize: 28, marginBottom: 10 }}>
        What would you like to focus on?
      </h1>
      <p style={{ opacity: 0.7, marginBottom: 30 }}>
        Choose one or more wellness goals. You can change these anytime.
      </p>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
          gap: 16,
          marginBottom: 40,
        }}
      >
        {OPTIONS.map((opt) => (
          <div
            key={opt.key}
            onClick={() => toggle(opt.key)}
            style={{
              padding: 20,
              borderRadius: 12,
              cursor: "pointer",
              border: selected.includes(opt.key)
                ? "2px solid #22c55e"
                : "1px solid #334155",
              background: selected.includes(opt.key)
                ? "rgba(34,197,94,0.1)"
                : "transparent",
            }}
          >
            <strong>{opt.label}</strong>
          </div>
        ))}
      </div>

      <button
        onClick={saveAndContinue}
        disabled={loading}
        style={{
          padding: "14px 28px",
          fontSize: 16,
          borderRadius: 999,
          background: "#22c55e",
          color: "#000",
          border: "none",
          cursor: "pointer",
        }}
      >
        {loading ? "Saving..." : "Continue"}
      </button>
    </main>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { alpha, useTheme } from "@mui/material/styles";
import {
  Box,
  Button,
  Card,
  CardContent,
  Stack,
  TextField,
  Typography,
  Alert,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Link,
  Divider,
} from "@mui/material";
import { login } from "@/lib/api";

import Lottie from "lottie-react";
import loginAi from "@/public/animations/login-ai.json";

export default function LoginPage() {
  const router = useRouter();
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  // IMPORTANT: start empty to keep SSR + client first render identical
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");

  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  const [fpOpen, setFpOpen] = useState(false);
  const [fpEmail, setFpEmail] = useState("");
  const [fpMsg, setFpMsg] = useState("");

  // OPTIONAL: set default username ONLY after mount (client-only)
  useEffect(() => {
    // If you don't want any default username, delete this block.
    setUsername((u) => u || "manas");
  }, []);

  const pageBg = useMemo(() => {
    const p = theme.palette.primary.main;
    const s = theme.palette.secondary.main;
    const ok = theme.palette.success.main;

    if (isDark) {
      return (
        `radial-gradient(1200px 650px at 15% 0%, ${alpha(p, 0.18)}, transparent 60%),` +
        `radial-gradient(900px 520px at 85% 20%, ${alpha(s, 0.18)}, transparent 55%),` +
        `radial-gradient(900px 520px at 50% 110%, ${alpha(ok, 0.10)}, transparent 55%),` +
        `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
      );
    }

    return (
      `radial-gradient(1100px 520px at 12% 0%, ${alpha(p, 0.12)}, transparent 60%),` +
      `radial-gradient(900px 480px at 90% 10%, ${alpha(s, 0.12)}, transparent 60%),` +
      `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
    );
  }, [theme, isDark]);

  const border = useMemo(
    () => `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
    [theme, isDark]
  );

  const lottieWrap = useMemo(
    () => ({
      width: "100%",
      maxWidth: 360,
      borderRadius: 6,
      p: 1.2,
      border,
      overflow: "hidden",
      background: isDark
        ? `linear-gradient(135deg, ${alpha("#0f172a", 0.55)}, ${alpha("#020617", 0.48)})`
        : `linear-gradient(135deg, ${alpha("#ffffff", 0.70)}, ${alpha(
            theme.palette.primary.main,
            0.06
          )})`,
      boxShadow: isDark ? "0 22px 70px rgba(0,0,0,0.45)" : "0 18px 60px rgba(2,6,23,0.08)",
      backdropFilter: "blur(12px)",
      position: "relative",
    }),
    [theme, isDark, border]
  );

  const loginCard = useMemo(
    () => ({
      width: "100%",
      borderRadius: 6,
      overflow: "hidden",
      border,
      boxShadow: isDark ? "0 35px 120px rgba(0,0,0,0.55)" : "0 22px 70px rgba(2,6,23,0.10)",
      background: isDark
        ? `linear-gradient(180deg, ${alpha(theme.palette.background.paper, 0.22)}, ${alpha(
            theme.palette.background.paper,
            0.12
          )})`
        : `linear-gradient(180deg, ${alpha("#ffffff", 0.78)}, ${alpha("#ffffff", 0.55)})`,
      backdropFilter: "blur(14px)",
    }),
    [theme, isDark, border]
  );

  const inputSx = useMemo(
    () => ({
      "& .MuiInputBase-root": {
        borderRadius: 3,
        background: isDark ? alpha("#020617", 0.22) : alpha("#ffffff", 0.70),
        backdropFilter: "blur(10px)",
      },
      "& .MuiOutlinedInput-notchedOutline": {
        borderColor: alpha(theme.palette.text.primary, isDark ? 0.22 : 0.16),
      },
      "&:hover .MuiOutlinedInput-notchedOutline": {
        borderColor: alpha(theme.palette.text.primary, isDark ? 0.35 : 0.22),
      },
      "& .MuiInputLabel-root": {
        color: alpha(theme.palette.text.primary, isDark ? 0.70 : 0.65),
        fontWeight: 700,
      },
    }),
    [theme, isDark]
  );

  const onLogin = async () => {
    setErr("");

    const u = username.trim();
    if (!u) return setErr("Please enter a username.");
    if (!password) return setErr("Please enter your password.");

    setLoading(true);
    try {
      await login(u, password);
      router.push("/dashboard");
    } catch (e: any) {
      setErr("Login failed. Check username/password and Django server.");
    } finally {
      setLoading(false);
    }
  };

  const openForgot = () => {
    setFpEmail("");
    setFpMsg("");
    setFpOpen(true);
  };

  const submitForgot = () => {
    const email = fpEmail.trim();
    if (!email || !email.includes("@")) {
      setFpMsg("Enter a valid email address.");
      return;
    }

    setFpMsg("Request created. Please check your email (or contact support).");
    // Keep it inside handler (client-only)
    window.open(
      `mailto:support@praxiaone.com?subject=Password%20Reset%20Request&body=Please%20reset%20my%20password%20for%20email:%20${encodeURIComponent(
        email
      )}`,
      "_blank"
    );
  };

  return (
    <Box
      sx={{
        minHeight: "calc(100vh - 24px)",
        display: "grid",
        placeItems: "center",
        px: 2,
        py: 6,
        background: pageBg,
      }}
    >
      <Box sx={{ width: "100%", maxWidth: 520 }}>
        {/* Animation */}
        <Box sx={{ display: "grid", placeItems: "center", mb: 2 }}>
          <Box sx={lottieWrap}>
            {/* subtle aura */}
            <Box
              sx={{
                position: "absolute",
                inset: -80,
                background:
                  `radial-gradient(circle at 30% 30%, ${alpha(
                    theme.palette.primary.main,
                    isDark ? 0.18 : 0.12
                  )}, transparent 55%),` +
                  `radial-gradient(circle at 70% 30%, ${alpha(
                    theme.palette.secondary.main,
                    isDark ? 0.18 : 0.12
                  )}, transparent 55%),` +
                  `radial-gradient(circle at 50% 80%, ${alpha(
                    theme.palette.success.main,
                    isDark ? 0.12 : 0.10
                  )}, transparent 55%)`,
                filter: "blur(14px)",
                pointerEvents: "none",
              }}
            />

            <Box sx={{ position: "relative" }}>
              <Lottie animationData={loginAi} loop autoplay style={{ width: "100%", height: 220 }} />
            </Box>
          </Box>
        </Box>

        {/* Login Card */}
        <Card sx={loginCard}>
          <CardContent sx={{ p: 3 }}>
            <Typography
              variant="h5"
              sx={{
                fontWeight: 950,
                mb: 1,
                color: isDark ? alpha("#F8FAFC", 0.96) : theme.palette.text.primary,
              }}
            >
              Log In
            </Typography>

            <Typography
              variant="body2"
              sx={{ mb: 2, color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}
            >
              Use your PraxiaOne account credentials.
            </Typography>

            {err && (
              <Alert severity="error" sx={{ mb: 2, borderRadius: 3 }}>
                {err}
              </Alert>
            )}

            {/* IMPORTANT: form-level autocomplete control */}
            <Box component="form" autoComplete="off" onSubmit={(e) => e.preventDefault()}>
              <Stack spacing={2}>
                <TextField
                  label="Username"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  fullWidth
                  sx={inputSx}
                  autoComplete="off"
                  inputProps={{
                    autoComplete: "off",
                    form: { autoComplete: "off" },
                  }}
                />

                <TextField
                  label="Password"
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  fullWidth
                  sx={inputSx}
                  autoComplete="new-password"
                  inputProps={{
                    autoComplete: "new-password",
                  }}
                />

                {/* Forgot password row */}
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Button
                    variant="text"
                    onClick={openForgot}
                    sx={{
                      textTransform: "none",
                      fontWeight: 900,
                      px: 0,
                      minWidth: 0,
                      color: isDark ? alpha("#E2E8F0", 0.86) : theme.palette.text.primary,
                      "&:hover": {
                        background: alpha(theme.palette.text.primary, isDark ? 0.06 : 0.04),
                      },
                    }}
                  >
                    Forgot password?
                  </Button>

                  <Link
                    href="/support"
                    underline="hover"
                    sx={{
                      fontSize: 13,
                      fontWeight: 800,
                      color: isDark ? alpha("#E2E8F0", 0.8) : theme.palette.text.primary,
                      opacity: 0.9,
                    }}
                  >
                    Need help?
                  </Link>
                </Stack>

                <Button
                  variant="contained"
                  color="success"
                  onClick={onLogin}
                  disabled={loading}
                  sx={{
                    borderRadius: 999,
                    fontWeight: 950,
                    py: 1.2,
                    boxShadow: isDark
                      ? "0 18px 55px rgba(0,0,0,0.35)"
                      : "0 18px 50px rgba(34,197,94,0.26)",
                  }}
                >
                  {loading ? "Logging in..." : "Log In"}
                </Button>

                <Divider sx={{ opacity: isDark ? 0.18 : 0.6 }} />

                <Typography
                  variant="caption"
                  sx={{ color: isDark ? alpha("#94A3B8", 0.78) : theme.palette.text.secondary }}
                >
                  By continuing, you agree to PraxiaOne’s Privacy Policy and Terms.
                </Typography>
              </Stack>
            </Box>
          </CardContent>
        </Card>

        {/* Forgot Password Dialog */}
        <Dialog open={fpOpen} onClose={() => setFpOpen(false)} fullWidth maxWidth="xs">
          <DialogTitle sx={{ fontWeight: 950 }}>Reset your password</DialogTitle>
          <DialogContent>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Enter your email. We’ll help you reset your password.
            </Typography>

            <TextField
              label="Email"
              value={fpEmail}
              onChange={(e) => setFpEmail(e.target.value)}
              fullWidth
              autoComplete="email"
            />

            {fpMsg && (
              <Alert
                severity={fpMsg.includes("valid") ? "error" : "success"}
                sx={{ mt: 2, borderRadius: 3 }}
              >
                {fpMsg}
              </Alert>
            )}
          </DialogContent>

          <DialogActions sx={{ p: 2 }}>
            <Button variant="outlined" onClick={() => setFpOpen(false)} sx={{ borderRadius: 999, fontWeight: 900 }}>
              Close
            </Button>
            <Button variant="contained" color="success" onClick={submitForgot} sx={{ borderRadius: 999, fontWeight: 900 }}>
              Send reset link
            </Button>
          </DialogActions>
        </Dialog>
      </Box>
    </Box>
  );
}

"use client";

import Link from "next/link";
import Image from "next/image";
import { useMemo } from "react";

import { alpha, useTheme } from "@mui/material/styles";

import {
  Box,
  Card,
  CardContent,
  Typography,
  Button,
  Chip,
  Stack,
  Grid,
  Divider,
} from "@mui/material";

import {
  VerifiedUser,
  Lock,
  ManageAccounts,
  Insights,
  Hub,
  Psychology,
  VideoCall,
} from "@mui/icons-material";

export default function HomePage() {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  const pageBg = useMemo(() => {
    const p = theme.palette.primary.main;
    const s = theme.palette.secondary.main;
    const ok = theme.palette.success.main;

    if (isDark) {
      return (
        `radial-gradient(1200px 650px at 15% 0%, ${alpha(p, 0.18)}, transparent 60%),` +
        `radial-gradient(900px 520px at 85% 20%, ${alpha(s, 0.18)}, transparent 55%),` +
        `radial-gradient(900px 520px at 50% 110%, ${alpha(ok, 0.12)}, transparent 55%),` +
        `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
      );
    }

    // Light (Classic)
    return (
      `radial-gradient(1100px 520px at 12% 0%, ${alpha(p, 0.12)}, transparent 60%),` +
      `radial-gradient(900px 480px at 90% 10%, ${alpha(s, 0.12)}, transparent 60%),` +
      `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
    );
  }, [theme, isDark]);

  const glassCard = useMemo(
    () => ({
      borderRadius: 8,
      overflow: "hidden",
      position: "relative",
      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
      background: isDark
        ? `linear-gradient(135deg, ${alpha("#0b1228", 0.90)}, ${alpha("#050816", 0.86)})`
        : `linear-gradient(135deg, ${alpha("#ffffff", 0.84)}, ${alpha(
            theme.palette.primary.main,
            0.05
          )}, ${alpha(theme.palette.secondary.main, 0.04)})`,
      boxShadow: isDark
        ? "0 35px 120px rgba(0,0,0,0.65)"
        : "0 26px 90px rgba(2,6,23,0.10)",
      backdropFilter: "blur(18px)",
    }),
    [theme, isDark]
  );

  const pillSx = useMemo(
    () => ({
      borderRadius: 999,
      fontWeight: 900,
      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.18 : 0.12)}`,
      color: isDark ? alpha("#E2E8F0", 0.92) : alpha(theme.palette.text.primary, 0.88),
      background: isDark
        ? `linear-gradient(90deg, ${alpha(theme.palette.primary.main, 0.16)}, ${alpha(
            theme.palette.secondary.main,
            0.14
          )})`
        : `linear-gradient(90deg, ${alpha(theme.palette.primary.main, 0.12)}, ${alpha(
            theme.palette.secondary.main,
            0.10
          )})`,
    }),
    [theme, isDark]
  );

  const features = useMemo(
    () => [
      {
        title: "Personalized Wellness Insights",
        desc: "Tailored health recommendations based on your inputs and consented data.",
        icon: <Insights />,
      },
      {
        title: "Secure Data Integration",
        desc: "Bring in self, labs, wearables, and EHR sources with controlled access.",
        icon: <Hub />,
      },
      {
        title: "AI-Assisted Guidance",
        desc: "Smart suggestions and summaries — designed to keep you in control.",
        icon: <Psychology />,
      },
      {
        title: "Optional Telehealth Access",
        desc: "Connect with providers (module-ready screen for future extension).",
        icon: <VideoCall />,
      },
    ],
    []
  );

  return (
    <Box
      sx={{
        minHeight: "calc(100vh - 24px)",
        py: 3,
        px: { xs: 2, md: 3 },
        background: pageBg,
      }}
    >
      {/* HERO */}
<Card
  sx={{
    mb: 3,
    borderRadius: 8,
    overflow: "hidden",
    position: "relative",
    minHeight: { xs: 420, md: 460 },
  }}
>
  {/* Background Image */}
  <Box sx={{ position: "absolute", inset: 0 }}>
    <Image
  src="/hearth-1674896_1280.webp"
  alt="Health background"
  fill
  priority
  style={{ objectFit: "cover" }}
/>


    {/* Theme-aware overlay */}
    <Box
      sx={{
        position: "absolute",
        inset: 0,
        background: isDark
          ? `
            linear-gradient(
              90deg,
              rgba(2,6,23,0.88) 0%,
              rgba(2,6,23,0.65) 55%,
              rgba(2,6,23,0.45) 100%
            )`
          : `
            linear-gradient(
              90deg,
              rgba(255,255,255,0.90) 0%,
              rgba(255,255,255,0.70) 55%,
              rgba(255,255,255,0.45) 100%
            )`,
      }}
    />
  </Box>

  {/* Overlay Content */}
  <CardContent
    sx={{
      position: "relative",
      zIndex: 1,
      p: { xs: 3, md: 4 },
      height: "100%",
      display: "flex",
      alignItems: "center",
    }}
  >
    <Grid container spacing={3}>
      <Grid item xs={12} md={7}>
        <Stack spacing={2}>
          <Chip
            label="PraxiaOne — AI-Driven Personalized Wellness"
            size="small"
            sx={{
              width: "fit-content",
              fontWeight: 900,
              borderRadius: 999,
              backdropFilter: "blur(10px)",
              background: isDark
                ? "rgba(15,23,42,0.55)"
                : "rgba(255,255,255,0.65)",
            }}
          />

          <Typography
            variant="h3"
            sx={{
              fontWeight: 950,
              letterSpacing: "-0.04em",
              color: isDark ? "#F8FAFC" : "#020617",
              textShadow: isDark
                ? "0 12px 35px rgba(0,0,0,0.65)"
                : "0 8px 20px rgba(0,0,0,0.12)",
            }}
          >
            Your Health, Your Data, Your Way
          </Typography>

          <Typography
            sx={{
              maxWidth: 700,
              color: isDark
                ? "rgba(226,232,240,0.85)"
                : "rgba(15,23,42,0.75)",
            }}
          >
            Connect labs, care plans, wearables, and self-reported wellness — then
            get AI-assisted guidance you fully control.
          </Typography>

          <Stack direction="row" spacing={1.2} flexWrap="wrap">
            <Button
              component={Link}
              href="/profile"
              variant="contained"
              color="success"
              sx={{
                borderRadius: 999,
                fontWeight: 900,
                px: 2.5,
                boxShadow: "0 18px 50px rgba(34,197,94,0.35)",
              }}
            >
              Get Started
            </Button>

            <Button
              component={Link}
              href="/login"
              variant="outlined"
              sx={{
                borderRadius: 999,
                fontWeight: 900,
                px: 2.5,
                color: isDark ? "#E2E8F0" : "#020617",
                borderColor: "rgba(148,163,184,0.45)",
                background: "rgba(255,255,255,0.15)",
                backdropFilter: "blur(10px)",
              }}
            >
              Log In
            </Button>
          </Stack>

          <Stack direction="row" spacing={1} flexWrap="wrap">
            <Chip icon={<VerifiedUser />} label="HIPAA Compliant" size="small" sx={pillSx} />
            <Chip icon={<Lock />} label="Secure & Encrypted" size="small" sx={pillSx} />
            <Chip icon={<ManageAccounts />} label="User Controlled Consent" size="small" sx={pillSx} />
          </Stack>
        </Stack>
      </Grid>
    </Grid>
  </CardContent>
</Card>


      {/* FEATURES */}
      <Grid container spacing={2.2}>
        {features.map((f) => (
          <Grid key={f.title} item xs={12} sm={6} md={3}>
            <Card
              sx={{
                borderRadius: 7,
                height: "100%",
                border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                background: isDark
                  ? `linear-gradient(180deg, ${alpha("#0f172a", 0.78)}, ${alpha("#020617", 0.70)})`
                  : `linear-gradient(180deg, ${alpha("#ffffff", 0.80)}, ${alpha("#ffffff", 0.58)})`,
                backdropFilter: "blur(14px)",
                boxShadow: isDark
                  ? "0 18px 70px rgba(0,0,0,0.38)"
                  : "0 18px 60px rgba(2,6,23,0.08)",
                transition: "transform 180ms ease, box-shadow 200ms ease",
                "&:hover": {
                  transform: "translateY(-4px)",
                  boxShadow: isDark
                    ? "0 28px 90px rgba(0,0,0,0.55)"
                    : "0 26px 80px rgba(2,6,23,0.12)",
                },
              }}
            >
              <CardContent sx={{ p: 2.4 }}>
                <Stack direction="row" spacing={1.2} alignItems="center" sx={{ mb: 1 }}>
                  <Box
                    sx={{
                      width: 42,
                      height: 42,
                      borderRadius: 3.5,
                      display: "grid",
                      placeItems: "center",
                      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                      background: `linear-gradient(135deg, ${alpha(
                        theme.palette.primary.main,
                        0.14
                      )}, ${alpha(theme.palette.secondary.main, 0.12)})`,
                      color: isDark ? alpha("#E2E8F0", 0.95) : theme.palette.text.primary,
                    }}
                  >
                    {f.icon}
                  </Box>
                  <Typography
                    sx={{
                      fontWeight: 950,
                      color: isDark ? alpha("#F8FAFC", 0.95) : theme.palette.text.primary,
                      letterSpacing: "-0.02em",
                    }}
                  >
                    {f.title}
                  </Typography>
                </Stack>

                <Typography
                  variant="body2"
                  sx={{ color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}
                >
                  {f.desc}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {/* FOOTER */}
      <Card
        sx={{
          mt: 3,
          borderRadius: 7,
          border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
          background: isDark
            ? `linear-gradient(180deg, ${alpha("#0f172a", 0.74)}, ${alpha("#020617", 0.68)})`
            : `linear-gradient(180deg, ${alpha("#ffffff", 0.82)}, ${alpha("#ffffff", 0.62)})`,
          backdropFilter: "blur(14px)",
          boxShadow: isDark ? "0 18px 70px rgba(0,0,0,0.35)" : "0 18px 60px rgba(2,6,23,0.08)",
        }}
      >
        <CardContent sx={{ p: 2.6 }}>
          <Stack
            direction={{ xs: "column", md: "row" }}
            alignItems={{ xs: "flex-start", md: "center" }}
            justifyContent="space-between"
            spacing={2}
          >
            <Stack spacing={1}>
              <Stack direction="row" spacing={1} flexWrap="wrap">
                <Chip icon={<VerifiedUser sx={{ fontSize: 18 }} />} label="HIPAA Compliant" size="small" sx={pillSx} />
                <Chip icon={<Lock sx={{ fontSize: 18 }} />} label="Secure & Encrypted" size="small" sx={pillSx} />
                <Chip icon={<ManageAccounts sx={{ fontSize: 18 }} />} label="User Controlled Consent" size="small" sx={pillSx} />
              </Stack>

              <Typography
                variant="caption"
                sx={{ color: isDark ? alpha("#94A3B8", 0.78) : theme.palette.text.secondary }}
              >
                PraxiaOne provides wellness guidance and is not a substitute for professional medical advice. Always consult a qualified provider for diagnosis or treatment.
              </Typography>
            </Stack>

            <Stack direction="row" spacing={2}>
              <FooterLink href="/consent" label="Privacy Policy" />
              <FooterLink href="/support" label="Contact Us" />
              <FooterLink href="/settings" label="Settings" />
            </Stack>
          </Stack>

          <Divider sx={{ mt: 2, opacity: isDark ? 0.15 : 0.25 }} />
          <Typography
            variant="caption"
            sx={{ display: "block", mt: 1.4, color: isDark ? alpha("#94A3B8", 0.70) : theme.palette.text.secondary }}
          >
            © {new Date().getFullYear()} PraxiaOne
          </Typography>
        </CardContent>
      </Card>
    </Box>
  );
}

function FooterLink({ href, label }: { href: string; label: string }) {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  return (
    <Button
      component={Link}
      href={href}
      variant="text"
      sx={{
        fontWeight: 900,
        borderRadius: 999,
        color: isDark ? alpha("#E2E8F0", 0.82) : theme.palette.text.primary,
        "&:hover": { background: alpha(theme.palette.text.primary, isDark ? 0.06 : 0.04) },
      }}
    >
      {label}
    </Button>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { alpha, useTheme } from "@mui/material/styles";
import {
  Box,
  Card,
  CardContent,
  Typography,
  Button,
  Stack,
  TextField,
  Chip,
  LinearProgress,
  Grid,
  Divider,
  Snackbar,
  Alert,
  InputAdornment,
  Tooltip,
  IconButton,
} from "@mui/material";
import {
  Person,
  Straighten,
  MonitorWeight,
  CalendarMonth,
  InfoOutlined,
  Bolt,
  VerifiedUser,
} from "@mui/icons-material";

import { apiFetch } from "@/lib/api";

type BackendProfile = {
  id?: number;
  user?: number;
  full_name: string;
  age: number | null;
  height_cm: number | null;
  weight_kg: number | null;
  diet_preference: string;
  notes: string;
  updated_at?: string;
};

type UiProfile = {
  full_name: string;
  age: string;
  height_cm: string;
  weight_kg: string;
  diet_preference: "Vegetarian" | "Non-Veg" | "Vegan" | "";
  notes: string;
  updated_at?: string;
};

function safeNum(v: any) {
  const n = Number(v);
  return Number.isFinite(n) ? n : NaN;
}

function bmiCategory(bmi: number) {
  if (!Number.isFinite(bmi)) return { label: "--", hint: "Add height + weight" };
  if (bmi < 18.5) return { label: "Underweight", hint: "Consider gradual healthy gain." };
  if (bmi < 25) return { label: "Normal", hint: "Great baseline — maintain consistency." };
  if (bmi < 30) return { label: "Overweight", hint: "Small changes = big wins." };
  return { label: "Obese", hint: "Start gentle — build sustainable habits." };
}

function toUi(b: BackendProfile): UiProfile {
  return {
    full_name: b.full_name || "",
    age: b.age === null || b.age === undefined ? "" : String(b.age),
    height_cm: b.height_cm === null || b.height_cm === undefined ? "" : String(b.height_cm),
    weight_kg: b.weight_kg === null || b.weight_kg === undefined ? "" : String(b.weight_kg),
    diet_preference: (b.diet_preference as any) || "Vegetarian",
    notes: b.notes || "",
    updated_at: b.updated_at,
  };
}

function toBackend(u: UiProfile): BackendProfile {
  const age = u.age.trim() === "" ? null : Number(u.age);
  const h = u.height_cm.trim() === "" ? null : Number(u.height_cm);
  const w = u.weight_kg.trim() === "" ? null : Number(u.weight_kg);

  return {
    full_name: u.full_name || "",
    age: Number.isFinite(age as any) ? (age as any) : null,
    height_cm: Number.isFinite(h as any) ? (h as any) : null,
    weight_kg: Number.isFinite(w as any) ? (w as any) : null,
    diet_preference: u.diet_preference || "",
    notes: u.notes || "",
  };
}

export default function ProfilePage() {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  const [data, setData] = useState<UiProfile>({
    full_name: "",
    age: "",
    height_cm: "",
    weight_kg: "",
    diet_preference: "Vegetarian",
    notes: "",
  });

  const [loading, setLoading] = useState(false);
  const [loadingInitial, setLoadingInitial] = useState(true);

  const [toast, setToast] = useState<{ open: boolean; msg: string; type: "success" | "error" }>(
    { open: false, msg: "", type: "success" }
  );

  // computed
  const heightCm = safeNum(data.height_cm);
  const weightKg = safeNum(data.weight_kg);

  const bmi = useMemo(() => {
    if (!Number.isFinite(heightCm) || !Number.isFinite(weightKg) || heightCm <= 0) return NaN;
    return weightKg / ((heightCm / 100) ** 2);
  }, [heightCm, weightKg]);

  const bmiText = Number.isFinite(bmi) ? bmi.toFixed(1) : "--";
  const bmiMeta = bmiCategory(bmi);

  const completion = useMemo(() => {
    const fields = [
      data.full_name?.trim(),
      data.age?.trim(),
      data.height_cm?.trim(),
      data.weight_kg?.trim(),
      data.diet_preference?.trim(),
      data.notes?.trim(),
    ];
    const filled = fields.filter((x) => String(x ?? "").trim().length > 0).length;
    return Math.min(100, Math.round((filled / fields.length) * 100));
  }, [data]);

  const lastSavedLabel = useMemo(() => {
    const d = data.updated_at ? new Date(data.updated_at) : null;
    if (!d || Number.isNaN(d.getTime())) return "Not saved yet";
    return `Last saved: ${d.toLocaleString()}`;
  }, [data.updated_at]);

  const pageBg = useMemo(() => {
    const p = theme.palette.primary.main;
    const s = theme.palette.secondary.main;
    const ok = theme.palette.success.main;

    if (isDark) {
      return (
        `radial-gradient(1200px 650px at 15% 0%, ${alpha(p, 0.18)}, transparent 60%),` +
        `radial-gradient(900px 520px at 85% 20%, ${alpha(s, 0.18)}, transparent 55%),` +
        `radial-gradient(900px 520px at 50% 110%, ${alpha(ok, 0.12)}, transparent 55%),` +
        `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
      );
    }

    return (
      `radial-gradient(1200px 650px at 15% 0%, ${alpha(p, 0.10)}, transparent 60%),` +
      `radial-gradient(900px 520px at 85% 20%, ${alpha(s, 0.10)}, transparent 55%),` +
      `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
    );
  }, [theme, isDark]);

  const surfaceCard = useMemo(
    () => ({
      borderRadius: 6,
      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
      boxShadow: isDark ? "0 28px 110px rgba(0,0,0,0.55)" : "0 16px 60px rgba(15,23,42,0.10)",
      overflow: "hidden" as const,
      background: isDark
        ? `linear-gradient(180deg, ${alpha("#0f172a", 0.82)}, ${alpha("#020617", 0.72)})`
        : `linear-gradient(180deg, ${alpha("#ffffff", 0.82)}, ${alpha("#ffffff", 0.58)})`,
      backdropFilter: "blur(12px)",
    }),
    [theme, isDark]
  );

  const pill = useMemo(
    () => ({
      fontWeight: 900,
      borderRadius: 999,
      border: 0,
      background: alpha(theme.palette.primary.main, isDark ? 0.18 : 0.12),
      color: isDark ? alpha("#E2E8F0", 0.92) : theme.palette.text.primary,
    }),
    [theme, isDark]
  );

  // ✅ Load profile from backend
  useEffect(() => {
    let mounted = true;
    (async () => {
      setLoadingInitial(true);
      try {
        const p = await apiFetch<BackendProfile>("/profile/", { method: "GET" });
        if (!mounted) return;
        setData(toUi(p));
      } catch {
        // If not logged in, keep editable UI but show it as "not saved yet"
      } finally {
        if (mounted) setLoadingInitial(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  const saveProfile = async () => {
    setLoading(true);
    try {
      const payload = toBackend(data);
      const saved = await apiFetch<BackendProfile>("/profile/", {
        method: "PUT",
        body: JSON.stringify(payload),
      });
      setData(toUi(saved));
      setToast({ open: true, msg: "Profile saved to server ✅", type: "success" });
    } catch (e: any) {
      setToast({
        open: true,
        msg: "Save failed ❌ (Are you logged in / server running?)",
        type: "error",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: "calc(100vh - 64px)",
        px: { xs: 2, md: 3 },
        py: { xs: 2, md: 3 },
        background: pageBg,
        animation: "fadeIn .35s ease-out",
        "@keyframes fadeIn": {
          from: { opacity: 0, transform: "translateY(6px)" },
          to: { opacity: 1, transform: "translateY(0px)" },
        },
      }}
    >
      <Card sx={{ ...surfaceCard, mb: 3, position: "relative" }}>
        <Box
          sx={{
            position: "absolute",
            inset: 0,
            pointerEvents: "none",
            background: isDark
              ? `radial-gradient(900px 300px at 18% 35%, ${alpha(theme.palette.primary.main, 0.22)}, transparent 60%),
                 radial-gradient(800px 320px at 80% 30%, ${alpha(theme.palette.secondary.main, 0.18)}, transparent 55%)`
              : `radial-gradient(700px 220px at 18% 35%, ${alpha(theme.palette.primary.main, 0.16)}, transparent 60%),
                 radial-gradient(600px 240px at 80% 30%, ${alpha(theme.palette.secondary.main, 0.14)}, transparent 55%)`,
          }}
        />

        <CardContent sx={{ position: "relative", py: 3 }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between" spacing={2}>
            <Box>
              <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 0.7 }} flexWrap="wrap">
                <Chip icon={<Bolt sx={{ fontSize: 18 }} />} label="AI-ready profile" size="small" sx={pill} />
                <Chip
                  icon={<VerifiedUser sx={{ fontSize: 18 }} />}
                  label="Server-backed"
                  size="small"
                  sx={{ ...pill, background: alpha(theme.palette.secondary.main, isDark ? 0.18 : 0.12) }}
                />
              </Stack>

              <Typography variant="h4" sx={{ fontWeight: 950, letterSpacing: -0.8 }}>
                Profile Setup
              </Typography>
              <Typography sx={{ color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}>
                Saved to server (Django) so other modules can use it with consent.
              </Typography>
            </Box>

            <Box sx={{ minWidth: 220, textAlign: "right" }}>
              <Typography variant="caption" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                Profile completeness
              </Typography>

              <Stack direction="row" spacing={1} alignItems="center" justifyContent="flex-end">
                <Box sx={{ width: 160 }}>
                  <LinearProgress
                    variant="determinate"
                    value={completion}
                    sx={{
                      height: 10,
                      borderRadius: 999,
                      backgroundColor: alpha(theme.palette.text.primary, isDark ? 0.12 : 0.08),
                      "& .MuiLinearProgress-bar": {
                        borderRadius: 999,
                        background: `linear-gradient(90deg, ${theme.palette.primary.main}, ${theme.palette.secondary.main})`,
                      },
                    }}
                  />
                </Box>

                <Chip
                  label={`${completion}%`}
                  size="small"
                  sx={{
                    fontWeight: 950,
                    borderRadius: 999,
                    background: alpha(theme.palette.text.primary, isDark ? 0.10 : 0.06),
                    color: isDark ? alpha("#E2E8F0", 0.92) : theme.palette.text.primary,
                  }}
                />
              </Stack>

              <Typography
                variant="caption"
                sx={{
                  display: "block",
                  mt: 0.8,
                  color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary,
                }}
              >
                {loadingInitial ? "Loading..." : lastSavedLabel}
              </Typography>
            </Box>
          </Stack>
        </CardContent>
      </Card>

      <Grid container spacing={3} alignItems="stretch">
        <Grid item xs={12} lg={8}>
          <Card sx={surfaceCard}>
            <Box
              sx={{
                px: 3,
                py: 2,
                borderBottom: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.12 : 0.10)}`,
                background: isDark
                  ? `linear-gradient(90deg, ${alpha(theme.palette.primary.main, 0.16)}, ${alpha(theme.palette.secondary.main, 0.10)})`
                  : `linear-gradient(90deg, ${alpha(theme.palette.primary.main, 0.10)}, ${alpha(theme.palette.secondary.main, 0.06)})`,
              }}
            >
              <Stack direction="row" alignItems="center" justifyContent="space-between">
                <Typography sx={{ fontWeight: 900 }}>Basic details</Typography>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <Typography variant="caption" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                    Tip: More details → better insights
                  </Typography>
                  <Tooltip title="Only consented categories are used for AI insights.">
                    <IconButton size="small">
                      <InfoOutlined fontSize="small" />
                    </IconButton>
                  </Tooltip>
                </Stack>
              </Stack>
            </Box>

            <CardContent sx={{ p: 3 }}>
              <Grid container spacing={2}>
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="Full Name"
                    value={data.full_name}
                    onChange={(e) => setData({ ...data, full_name: e.target.value })}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <Person fontSize="small" />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="Age"
                    value={data.age}
                    onChange={(e) => setData({ ...data, age: e.target.value })}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <CalendarMonth fontSize="small" />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="Height (cm)"
                    value={data.height_cm}
                    onChange={(e) => setData({ ...data, height_cm: e.target.value })}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <Straighten fontSize="small" />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="Weight (kg)"
                    value={data.weight_kg}
                    onChange={(e) => setData({ ...data, weight_kg: e.target.value })}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <MonitorWeight fontSize="small" />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12}>
                  <Typography variant="caption" sx={{ display: "block", mb: 1, color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                    Diet preference
                  </Typography>

                  <Stack direction="row" spacing={1} flexWrap="wrap">
                    {(["Vegetarian", "Non-Veg", "Vegan"] as const).map((d) => {
                      const selected = data.diet_preference === d;
                      return (
                        <Chip
                          key={d}
                          label={d}
                          onClick={() => setData({ ...data, diet_preference: d })}
                          sx={{
                            fontWeight: 900,
                            borderRadius: 999,
                            px: 0.6,
                            cursor: "pointer",
                            background: selected
                              ? alpha(theme.palette.success.main, isDark ? 0.22 : 0.14)
                              : alpha(theme.palette.text.primary, isDark ? 0.10 : 0.06),
                          }}
                        />
                      );
                    })}
                  </Stack>
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Notes / Preferences"
                    multiline
                    rows={3}
                    value={data.notes}
                    onChange={(e) => setData({ ...data, notes: e.target.value })}
                  />
                </Grid>
              </Grid>

              <Divider sx={{ my: 2.5, opacity: isDark ? 0.12 : 0.25 }} />

              <Stack direction={{ xs: "column", sm: "row" }} spacing={1.5} alignItems="center" justifyContent="space-between">
                <Typography variant="caption" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                  Saved to backend so AI + other screens can use it (with consent).
                </Typography>

                <Button
                  variant="contained"
                  color="success"
                  onClick={saveProfile}
                  disabled={loading}
                  sx={{ borderRadius: 999, fontWeight: 950, px: 3 }}
                >
                  {loading ? "Saving..." : "Save Profile"}
                </Button>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} lg={4}>
          <Card sx={surfaceCard}>
            <CardContent sx={{ p: 3 }}>
              <Typography sx={{ fontWeight: 950, mb: 0.4 }}>Your profile preview</Typography>
              <Typography variant="caption" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                BMI + diet summary
              </Typography>

              <Divider sx={{ my: 2, opacity: isDark ? 0.12 : 0.25 }} />

              <Stack spacing={1}>
                <Row label="Name" value={data.full_name?.trim() || "--"} />
                <Row label="Diet" value={data.diet_preference || "--"} />
                <Row label="BMI" value={bmiText} />
                <Row label="BMI Category" value={bmiMeta.label} />
              </Stack>

              <Box
                sx={{
                  mt: 2,
                  p: 1.3,
                  borderRadius: 3,
                  background: alpha(theme.palette.primary.main, isDark ? 0.14 : 0.10),
                  border: `1px solid ${alpha(theme.palette.primary.main, isDark ? 0.22 : 0.16)}`,
                }}
              >
                <Typography variant="caption" sx={{ fontWeight: 900 }}>
                  Insight hint:
                </Typography>
                <Typography variant="caption" sx={{ display: "block", opacity: 0.8 }}>
                  {bmiMeta.hint}
                </Typography>
              </Box>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Snackbar open={toast.open} autoHideDuration={2200} onClose={() => setToast((t) => ({ ...t, open: false }))} anchorOrigin={{ vertical: "bottom", horizontal: "left" }}>
        <Alert severity={toast.type} variant="filled" onClose={() => setToast((t) => ({ ...t, open: false }))} sx={{ borderRadius: 3 }}>
          {toast.msg}
        </Alert>
      </Snackbar>
    </Box>
  );
}

function Row({ label, value }: { label: string; value: string }) {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  return (
    <Stack direction="row" justifyContent="space-between" alignItems="center">
      <Typography variant="body2" sx={{ fontWeight: 800 }}>
        {label}
      </Typography>
      <Typography variant="body2" sx={{ fontWeight: 700, color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
        {value}
      </Typography>
    </Stack>
  );
}

