"use client";

import { useEffect, useMemo, useState } from "react";
import Lottie from "lottie-react";
import Link from "next/link";

import { alpha, useTheme } from "@mui/material/styles";

import {
  Box,
  Card,
  CardContent,
  Typography,
  Chip,
  Button,
  Divider,
  Grid,
  TextField,
  InputAdornment,
  MenuItem,
  LinearProgress,
  Snackbar,
  Alert,
  Paper,
  Avatar,
  Tooltip,
  IconButton,
  Stack,
  Skeleton,
} from "@mui/material";

import {
  Help as HelpIcon,
  SupportAgent,
  BugReport,
  Feedback,
  Security,
  AttachFile,
  Send,
  CheckCircle,
  InfoOutlined,
  ArrowForward,
  ContentCopy,
  MailOutline,
  LiveHelp,
  Schedule,
} from "@mui/icons-material";

type FormState = {
  category: "Bug" | "Account" | "Feature request" | "Feedback" | "Other";
  subject: string;
  message: string;
  email: string;
  priority: "Low" | "Normal" | "High";
  includeDiagnostics: boolean;
};

const STORAGE_KEY = "praxiaone_support_drafts_v1";

function safeParse<T>(raw: string | null): T | null {
  if (!raw) return null;
  try {
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

function clamp(n: number, min: number, max: number) {
  return Math.max(min, Math.min(max, n));
}

function useLottieJson(url: string) {
  const [data, setData] = useState<any>(null);

  useEffect(() => {
    let alive = true;

    fetch(url)
      .then((r) => r.json())
      .then((json) => {
        if (!alive) return;
        setData(json);
      })
      .catch(() => {
        if (!alive) return;
        setData(null);
      });

    return () => {
      alive = false;
    };
  }, [url]);

  return data;
}

export default function SupportPage() {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  // ✅ ensure file exists: frontend/public/animations/support.json
  const supportAnim = useLottieJson("/animations/support.json");

  const [form, setForm] = useState<FormState>({
    category: "Feedback",
    subject: "",
    message: "",
    email: "",
    priority: "Normal",
    includeDiagnostics: true,
  });

  const [sending, setSending] = useState(false);
  const [submittedPulse, setSubmittedPulse] = useState(false);

  const [toast, setToast] = useState<{
    open: boolean;
    msg: string;
    type: "success" | "info" | "warning" | "error";
  }>({ open: false, msg: "", type: "success" });

  const [draftSavedAt, setDraftSavedAt] = useState<string | null>(null);

  useEffect(() => {
    const saved = safeParse<FormState>(localStorage.getItem(STORAGE_KEY));
    if (saved) setForm((p) => ({ ...p, ...saved }));
    const t = localStorage.getItem(`${STORAGE_KEY}_ts`);
    if (t) setDraftSavedAt(t);
  }, []);

  useEffect(() => {
    const id = setTimeout(() => {
      try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(form));
        const ts = new Date().toLocaleString();
        localStorage.setItem(`${STORAGE_KEY}_ts`, ts);
        setDraftSavedAt(ts);
      } catch {}
    }, 500);
    return () => clearTimeout(id);
  }, [form]);

  const progress = useMemo(() => {
    const a = form.subject.trim().length > 0 ? 1 : 0;
    const b = form.message.trim().length >= 20 ? 1 : 0;
    const c = form.category ? 1 : 0;
    const d = form.email.trim().length > 3 ? 1 : 0;
    return Math.round(((a + b + c + d) / 4) * 100);
  }, [form]);

  const helperHint = useMemo(() => {
    if (progress < 25) return "Start with a clear subject + what you expected vs what happened.";
    if (progress < 50) return "Add steps to reproduce or a screenshot note to speed up help.";
    if (progress < 75) return "Nice. Add device/browser details if it’s a UI issue.";
    return "Perfect. Ready to send ✅";
  }, [progress]);

  const categoryIcon = useMemo(() => {
    switch (form.category) {
      case "Bug":
        return <BugReport sx={{ fontSize: 18 }} />;
      case "Account":
        return <Security sx={{ fontSize: 18 }} />;
      case "Feature request":
        return <LiveHelp sx={{ fontSize: 18 }} />;
      case "Feedback":
        return <Feedback sx={{ fontSize: 18 }} />;
      default:
        return <HelpIcon sx={{ fontSize: 18 }} />;
    }
  }, [form.category]);

  const onChange = <K extends keyof FormState>(key: K, value: FormState[K]) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const reset = () => {
    setForm({
      category: "Feedback",
      subject: "",
      message: "",
      email: "",
      priority: "Normal",
      includeDiagnostics: true,
    });
    setToast({ open: true, msg: "Cleared form (draft autosave updated).", type: "info" });
  };

  const copyTemplate = async () => {
    const template =
      `Category: ${form.category}\n` +
      `Priority: ${form.priority}\n` +
      `Subject: ${form.subject || "(add subject)"}\n\n` +
      `What happened?\n- \n\nWhat did you expect?\n- \n\nSteps to reproduce:\n1) \n2) \n3) \n\nEnvironment:\n- Browser: \n- OS: \n- Page URL: /support\n`;
    try {
      await navigator.clipboard.writeText(template);
      setToast({ open: true, msg: "Copied a helpful support template ✅", type: "success" });
    } catch {
      setToast({ open: true, msg: "Could not copy to clipboard.", type: "warning" });
    }
  };

  const submit = async () => {
    if (!form.subject.trim()) {
      setToast({ open: true, msg: "Please add a subject.", type: "warning" });
      return;
    }
    if (form.message.trim().length < 20) {
      setToast({ open: true, msg: "Message is too short. Add a little more detail.", type: "warning" });
      return;
    }

    setSending(true);
    setToast({ open: true, msg: "Sending… (demo)", type: "info" });

    await new Promise((r) => setTimeout(r, 900));

    setSending(false);
    setSubmittedPulse(true);
    setTimeout(() => setSubmittedPulse(false), 900);

    setToast({ open: true, msg: "Submitted! (demo) ✅ No backend hooked yet.", type: "success" });
  };

  const pageBg = useMemo(() => {
    const p = theme.palette.primary.main;
    const s = theme.palette.secondary.main;
    const ok = theme.palette.success.main;

    if (isDark) {
      return (
        `radial-gradient(1200px 650px at 15% 0%, ${alpha(p, 0.18)}, transparent 60%),` +
        `radial-gradient(900px 520px at 85% 20%, ${alpha(s, 0.18)}, transparent 55%),` +
        `radial-gradient(900px 520px at 50% 110%, ${alpha(ok, 0.12)}, transparent 55%),` +
        `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
      );
    }

    return (
      `radial-gradient(1100px 520px at 12% 0%, ${alpha(p, 0.12)}, transparent 60%),` +
      `radial-gradient(900px 480px at 90% 10%, ${alpha(s, 0.12)}, transparent 60%),` +
      `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
    );
  }, [theme, isDark]);

  const AnimatedCardSx = useMemo(
    () => ({
      borderRadius: 6,
      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
      boxShadow: isDark ? "0 28px 110px rgba(0,0,0,0.55)" : "0 16px 60px rgba(15,23,42,0.10)",
      background: isDark
        ? `linear-gradient(180deg, ${alpha("#0f172a", 0.80)}, ${alpha("#020617", 0.72)})`
        : `linear-gradient(180deg, ${alpha("#ffffff", 0.86)}, ${alpha("#ffffff", 0.62)})`,
      backdropFilter: "blur(14px)",
      transition: "transform 220ms ease, box-shadow 220ms ease",
      "&:hover": {
        transform: "translateY(-4px)",
        boxShadow: isDark ? "0 38px 140px rgba(0,0,0,0.65)" : "0 22px 70px rgba(15,23,42,0.12)",
      },
    }),
    [theme, isDark]
  );

  return (
    <Box
      sx={{
        minHeight: "calc(100vh - 24px)",
        px: { xs: 2, md: 3 },
        py: { xs: 2, md: 3 },
        background: pageBg,
        "@keyframes pageIn": {
          from: { opacity: 0, transform: "translateY(10px)" },
          to: { opacity: 1, transform: "translateY(0px)" },
        },
        "@keyframes shimmer": {
          "0%": { backgroundPosition: "-200px 0" },
          "100%": { backgroundPosition: "200px 0" },
        },
        "@keyframes pulseOk": {
          "0%": { transform: "scale(1)" },
          "50%": { transform: "scale(1.02)" },
          "100%": { transform: "scale(1)" },
        },
        animation: "pageIn .45s ease-out",
      }}
    >
      {/* HERO */}
      <Card
        sx={{
          ...AnimatedCardSx,
          mb: 3,
          overflow: "hidden",
          position: "relative",
        }}
      >
        <CardContent sx={{ position: "relative", py: 3 }}>
          <Grid container spacing={2} alignItems="center">
            <Grid item xs={12} md={7}>
              <Stack direction="row" spacing={2} alignItems="center">
                <Avatar
                  sx={{
                    width: 54,
                    height: 54,
                    fontWeight: 950,
                    boxShadow: isDark ? "0 18px 40px rgba(0,0,0,0.40)" : "0 18px 40px rgba(15,23,42,0.10)",
                    background: isDark ? alpha("#0b1228", 0.70) : alpha("#ffffff", 0.80),
                    color: theme.palette.primary.main,
                    border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                  }}
                >
                  <SupportAgent />
                </Avatar>

                <Box>
                  <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 0.6, flexWrap: "wrap" }}>
                    <Chip
                      icon={<HelpIcon sx={{ fontSize: 18 }} />}
                      label="Help / Support"
                      size="small"
                      sx={{
                        fontWeight: 950,
                        borderRadius: 999,
                        background: alpha(theme.palette.primary.main, isDark ? 0.18 : 0.12),
                      }}
                    />
                    <Chip
                      icon={<CheckCircle sx={{ fontSize: 18 }} />}
                      label="Fast triage"
                      size="small"
                      sx={{
                        fontWeight: 950,
                        borderRadius: 999,
                        background: alpha(theme.palette.text.primary, isDark ? 0.10 : 0.06),
                        color: isDark ? alpha("#E2E8F0", 0.92) : theme.palette.text.primary,
                      }}
                    />
                    <Chip
                      icon={<Schedule sx={{ fontSize: 18 }} />}
                      label={draftSavedAt ? `Draft saved: ${draftSavedAt}` : "Draft autosave: on"}
                      size="small"
                      sx={{
                        fontWeight: 950,
                        borderRadius: 999,
                        background: alpha(theme.palette.text.primary, isDark ? 0.10 : 0.06),
                        color: isDark ? alpha("#E2E8F0", 0.92) : theme.palette.text.primary,
                        maxWidth: 520,
                      }}
                    />
                  </Stack>

                  <Typography variant="h4" sx={{ fontWeight: 950, letterSpacing: -0.8 }}>
                    How can we help?
                  </Typography>
                  <Typography sx={{ color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}>
                    Tell us what’s happening — the more detail, the faster the fix (demo submission).
                  </Typography>
                </Box>
              </Stack>
            </Grid>

            <Grid item xs={12} md={5}>
              <Box
                sx={{
                  borderRadius: 6,
                  border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                  background: isDark
                    ? `linear-gradient(135deg, ${alpha("#0f172a", 0.55)}, ${alpha("#020617", 0.45)})`
                    : `linear-gradient(135deg, ${alpha("#ffffff", 0.70)}, ${alpha(theme.palette.primary.main, 0.06)})`,
                  overflow: "hidden",
                  position: "relative",
                  p: 1.5,
                }}
              >
                {!supportAnim ? (
                  <Skeleton variant="rounded" height={220} />
                ) : (
                  <Lottie animationData={supportAnim} loop autoplay style={{ width: "100%", height: 220 }} />
                )}
              </Box>
            </Grid>
          </Grid>

          <Divider sx={{ my: 2, opacity: isDark ? 0.12 : 0.25 }} />

          <Stack
            direction={{ xs: "column", md: "row" }}
            alignItems={{ xs: "flex-start", md: "center" }}
            justifyContent="space-between"
            spacing={2}
          >
            <Stack spacing={0.8} sx={{ minWidth: { xs: "100%", md: 520 } }}>
              <Stack direction="row" spacing={1} justifyContent="space-between" alignItems="center">
                <Chip
                  icon={categoryIcon}
                  label={`Category: ${form.category}`}
                  size="small"
                  sx={{
                    fontWeight: 950,
                    borderRadius: 999,
                    background: alpha(theme.palette.text.primary, isDark ? 0.10 : 0.06),
                    color: isDark ? alpha("#E2E8F0", 0.92) : theme.palette.text.primary,
                  }}
                />
                <Tooltip title="Demo mode: this does not send an actual ticket yet.">
                  <IconButton
                    onClick={() =>
                      setToast({
                        open: true,
                        msg: "Demo mode: we can connect this form to Django later.",
                        type: "info",
                      })
                    }
                  >
                    <InfoOutlined />
                  </IconButton>
                </Tooltip>
              </Stack>

              <Box>
                <Typography variant="caption" sx={{ fontWeight: 900, color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}>
                  Ticket readiness: {progress}%
                </Typography>

                <LinearProgress
                  variant="determinate"
                  value={clamp(progress, 0, 100)}
                  sx={{
                    height: 10,
                    borderRadius: 999,
                    background: alpha(theme.palette.text.primary, isDark ? 0.12 : 0.08),
                    overflow: "hidden",
                    "& .MuiLinearProgress-bar": {
                      borderRadius: 999,
                      position: "relative",
                      background: `linear-gradient(90deg, ${theme.palette.primary.main}, ${theme.palette.secondary.main})`,
                    },
                    "& .MuiLinearProgress-bar::after": {
                      content: '""',
                      position: "absolute",
                      inset: 0,
                      background:
                        "linear-gradient(90deg, rgba(255,255,255,0.0), rgba(255,255,255,0.45), rgba(255,255,255,0.0))",
                      backgroundSize: "200px 100%",
                      animation: progress > 0 ? "shimmer 1.6s linear infinite" : "none",
                      opacity: 0.7,
                    },
                  }}
                />

                <Typography variant="caption" sx={{ display: "block", mt: 0.8, color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}>
                  Tip: {helperHint}
                </Typography>
              </Box>

              <Stack direction="row" spacing={1} sx={{ pt: 0.6 }}>
                <Button
                  size="small"
                  variant="outlined"
                  startIcon={<ContentCopy />}
                  onClick={copyTemplate}
                  sx={{ borderRadius: 999, fontWeight: 950 }}
                >
                  Copy template
                </Button>
                <Button
                  size="small"
                  variant="contained"
                  color="success"
                  startIcon={<Send />}
                  onClick={submit}
                  disabled={sending}
                  sx={{
                    borderRadius: 999,
                    fontWeight: 950,
                    boxShadow: isDark ? "0 18px 50px rgba(34,197,94,0.35)" : "0 14px 40px rgba(34,197,94,0.22)",
                  }}
                >
                  {sending ? "Submitting…" : "Submit"}
                </Button>
              </Stack>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      <Grid container spacing={3}>
        {/* FORM */}
        <Grid item xs={12} lg={8}>
          <Card sx={AnimatedCardSx}>
            <CardContent sx={{ p: 3 }}>
              <Stack direction="row" alignItems="center" justifyContent="space-between" sx={{ mb: 1 }}>
                <Stack direction="row" spacing={1} alignItems="center">
                  <SupportAgent />
                  <Typography sx={{ fontWeight: 950 }}>Create a support ticket</Typography>
                </Stack>
                <Chip
                  icon={<Security sx={{ fontSize: 18 }} />}
                  label="Privacy-first"
                  size="small"
                  sx={{
                    fontWeight: 950,
                    borderRadius: 999,
                    background: alpha(theme.palette.primary.main, isDark ? 0.18 : 0.12),
                  }}
                />
              </Stack>

              <Typography variant="body2" sx={{ color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary, mb: 2 }}>
                Share only what you’re comfortable with. You’re always in control.
              </Typography>

              <Divider sx={{ mb: 2, opacity: isDark ? 0.12 : 0.25 }} />

              <Grid container spacing={2}>
                <Grid item xs={12} md={6}>
                  <TextField
                    select
                    fullWidth
                    label="Category"
                    value={form.category}
                    onChange={(e) => onChange("category", e.target.value as FormState["category"])}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          {form.category === "Bug" ? (
                            <BugReport />
                          ) : form.category === "Account" ? (
                            <Security />
                          ) : form.category === "Feature request" ? (
                            <LiveHelp />
                          ) : form.category === "Feedback" ? (
                            <Feedback />
                          ) : (
                            <HelpIcon />
                          )}
                        </InputAdornment>
                      ),
                    }}
                  >
                    <MenuItem value="Bug">Bug</MenuItem>
                    <MenuItem value="Account">Account</MenuItem>
                    <MenuItem value="Feature request">Feature request</MenuItem>
                    <MenuItem value="Feedback">Feedback</MenuItem>
                    <MenuItem value="Other">Other</MenuItem>
                  </TextField>
                </Grid>

                <Grid item xs={12} md={6}>
                  <TextField
                    select
                    fullWidth
                    label="Priority"
                    value={form.priority}
                    onChange={(e) => onChange("priority", e.target.value as FormState["priority"])}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <Schedule />
                        </InputAdornment>
                      ),
                    }}
                  >
                    <MenuItem value="Low">Low</MenuItem>
                    <MenuItem value="Normal">Normal</MenuItem>
                    <MenuItem value="High">High</MenuItem>
                  </TextField>
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Subject"
                    value={form.subject}
                    onChange={(e) => onChange("subject", e.target.value)}
                    placeholder="e.g., Progress bar not updating on Vitals page"
                    inputProps={{ maxLength: 120 }}
                    helperText={`${form.subject.length}/120`}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <HelpIcon />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Message"
                    value={form.message}
                    onChange={(e) => onChange("message", e.target.value)}
                    placeholder={`Include:
• What happened?
• What you expected?
• Steps to reproduce
• Any screenshots or error text`}
                    multiline
                    minRows={6}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start" sx={{ alignSelf: "flex-start", mt: 1.5 }}>
                          <Feedback />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12} md={7}>
                  <TextField
                    fullWidth
                    label="Email (optional)"
                    value={form.email}
                    onChange={(e) => onChange("email", e.target.value)}
                    placeholder="So we can follow up"
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <MailOutline />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12} md={5}>
                  <Paper
                    elevation={0}
                    sx={{
                      p: 2,
                      borderRadius: 5,
                      height: "100%",
                      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                      background: alpha(theme.palette.background.paper, isDark ? 0.35 : 0.70),
                      transition: "transform 220ms ease",
                      "&:hover": { transform: "translateY(-2px)" },
                    }}
                  >
                    <Typography sx={{ fontWeight: 950, mb: 0.5 }}>Attachments</Typography>
                    <Typography variant="body2" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                      Coming soon. For now, paste the error text / steps.
                    </Typography>
                    <Button
                      fullWidth
                      variant="outlined"
                      startIcon={<AttachFile />}
                      disabled
                      sx={{ mt: 1.2, borderRadius: 999, fontWeight: 950 }}
                    >
                      Add file
                    </Button>
                  </Paper>
                </Grid>
              </Grid>

              <Divider sx={{ my: 2.5, opacity: isDark ? 0.12 : 0.25 }} />

              <Stack
                direction={{ xs: "column", md: "row" }}
                spacing={1.2}
                justifyContent="space-between"
                alignItems={{ xs: "stretch", md: "center" }}
              >
                <Stack direction="row" spacing={1} alignItems="center">
                  <Chip
                    label={form.includeDiagnostics ? "Diagnostics: Included (demo)" : "Diagnostics: Off"}
                    size="small"
                    sx={{
                      fontWeight: 950,
                      borderRadius: 999,
                      background: alpha(theme.palette.text.primary, isDark ? 0.10 : 0.06),
                      color: isDark ? alpha("#E2E8F0", 0.92) : theme.palette.text.primary,
                    }}
                  />
                  <Tooltip title="If enabled, we would attach non-sensitive device/app info to help debug.">
                    <IconButton onClick={() => onChange("includeDiagnostics", !form.includeDiagnostics)} size="small">
                      <InfoOutlined fontSize="small" />
                    </IconButton>
                  </Tooltip>
                </Stack>

                <Stack direction="row" spacing={1}>
                  <Button variant="outlined" onClick={reset} sx={{ borderRadius: 999, fontWeight: 950 }}>
                    Clear
                  </Button>
                  <Button
                    variant="contained"
                    color="success"
                    onClick={submit}
                    disabled={sending}
                    endIcon={<Send />}
                    sx={{
                      borderRadius: 999,
                      fontWeight: 950,
                      px: 2.5,
                      boxShadow: isDark ? "0 18px 50px rgba(34,197,94,0.35)" : "0 14px 40px rgba(34,197,94,0.22)",
                      animation: submittedPulse ? "pulseOk 900ms ease" : "none",
                    }}
                  >
                    {sending ? "Submitting…" : "Submit ticket"}
                  </Button>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* RIGHT PANEL */}
        <Grid item xs={12} lg={4}>
          <Card
            sx={{
              ...AnimatedCardSx,
              position: "sticky",
              top: 18,
            }}
          >
            <CardContent sx={{ p: 3 }}>
              <Stack direction="row" spacing={1} alignItems="center">
                <HelpIcon />
                <Typography sx={{ fontWeight: 950 }}>Quick help</Typography>
              </Stack>
              <Typography variant="body2" sx={{ mt: 1, color: isDark ? alpha("#E2E8F0", 0.72) : theme.palette.text.secondary }}>
                Try these first — they solve most issues in seconds.
              </Typography>

              <Divider sx={{ my: 2, opacity: isDark ? 0.12 : 0.25 }} />

              <Stack spacing={1.2}>
                <Paper
                  elevation={0}
                  sx={{
                    p: 2,
                    borderRadius: 5,
                    border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                    background: alpha(theme.palette.background.paper, isDark ? 0.30 : 0.70),
                  }}
                >
                  <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 0.5 }}>
                    <BugReport />
                    <Typography sx={{ fontWeight: 950 }}>If it’s a UI bug</Typography>
                  </Stack>
                  <Typography variant="body2" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                    Include page URL, steps, and what you saw vs expected.
                  </Typography>
                </Paper>

                <Paper
                  elevation={0}
                  sx={{
                    p: 2,
                    borderRadius: 5,
                    border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                    background: alpha(theme.palette.background.paper, isDark ? 0.30 : 0.70),
                  }}
                >
                  <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 0.5 }}>
                    <Security />
                    <Typography sx={{ fontWeight: 950 }}>Privacy note</Typography>
                  </Stack>
                  <Typography variant="body2" sx={{ color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                    Don’t paste passwords or full medical reports. Consent controls everything.
                  </Typography>
                </Paper>

                <Paper
                  elevation={0}
                  sx={{
                    p: 2,
                    borderRadius: 5,
                    border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.08)}`,
                    background: alpha(theme.palette.primary.main, isDark ? 0.12 : 0.08),
                  }}
                >
                  <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 0.6 }}>
                    <MailOutline />
                    <Typography sx={{ fontWeight: 950 }}>Contact options</Typography>
                  </Stack>
                  <Typography variant="body2" sx={{ mb: 1, color: isDark ? alpha("#E2E8F0", 0.70) : theme.palette.text.secondary }}>
                    For now, this is a placeholder. Later we can connect it to email + Django tickets.
                  </Typography>
                  <Button
                    component={Link}
                    href="/consent"
                    variant="outlined"
                    endIcon={<ArrowForward />}
                    sx={{ borderRadius: 999, fontWeight: 950 }}
                  >
                    Review Consent
                  </Button>
                </Paper>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Snackbar
        open={toast.open}
        autoHideDuration={2600}
        onClose={() => setToast((t) => ({ ...t, open: false }))}
        anchorOrigin={{ vertical: "bottom", horizontal: "left" }}
      >
        <Alert severity={toast.type} variant="filled" onClose={() => setToast((t) => ({ ...t, open: false }))} sx={{ borderRadius: 3 }}>
          {toast.msg}
        </Alert>
      </Snackbar>
    </Box>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { useTheme, alpha } from "@mui/material/styles";

import {
  Box,
  Card,
  CardContent,
  Typography,
  Stack,
  Button,
  Chip,
  Divider,
  LinearProgress,
  Alert,
  List,
  ListItem,
  ListItemText,
  IconButton,
  Tooltip,
} from "@mui/material";

import UploadFileRoundedIcon from "@mui/icons-material/UploadFileRounded";
import DescriptionRoundedIcon from "@mui/icons-material/DescriptionRounded";
import AutoAwesomeRoundedIcon from "@mui/icons-material/AutoAwesomeRounded";
import CheckCircleRoundedIcon from "@mui/icons-material/CheckCircleRounded";
import PictureAsPdfRoundedIcon from "@mui/icons-material/PictureAsPdfRounded";
import DeleteOutlineRoundedIcon from "@mui/icons-material/DeleteOutlineRounded";
import OpenInNewRoundedIcon from "@mui/icons-material/OpenInNewRounded";

const API = "http://127.0.0.1:8000/api";

type Doc = {
  id: number;
  doc_type: "care_plan" | "lab_result";
  title?: string;
  file: string;
  file_url?: string | null;
  uploaded_at: string;
};

function authHeadersJSON() {
  return {
    "Content-Type": "application/json",
    Authorization: `Bearer ${localStorage.getItem("access")}`,
  };
}

function authHeadersBearerOnly() {
  return {
    Authorization: `Bearer ${localStorage.getItem("access")}`,
  };
}

export default function UploadCarePlanPage() {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  const inputRef = useRef<HTMLInputElement | null>(null);

  const [file, setFile] = useState<File | null>(null);
  const [busy, setBusy] = useState(false);
  const [loadingList, setLoadingList] = useState(false);

  const [progress, setProgress] = useState(0);
  const [done, setDone] = useState(false);

  const [docs, setDocs] = useState<Doc[]>([]);
  const [err, setErr] = useState<string>("");

  const meta = useMemo(() => {
    if (!file) return null;
    const mb = (file.size / (1024 * 1024)).toFixed(2);
    return { name: file.name, mb };
  }, [file]);

  const pick = () => inputRef.current?.click();

  const onSelect = (f?: File | null) => {
    setErr("");
    setDone(false);
    setProgress(0);

    if (!f) {
      setFile(null);
      return;
    }

    const isPdf = f.type === "application/pdf" || f.name.toLowerCase().endsWith(".pdf");
    if (!isPdf) {
      setErr("Please select a PDF file only.");
      setFile(null);
      return;
    }

    if (f.size > 10 * 1024 * 1024) {
      setErr("Max 10MB allowed (demo). Please choose a smaller PDF.");
      setFile(null);
      return;
    }

    setFile(f);
  };

  const loadCarePlans = async () => {
    setLoadingList(true);
    setErr("");
    try {
      const res = await fetch(`${API}/documents/?type=care_plan`, {
        headers: authHeadersBearerOnly(),
      });

      if (!res.ok) {
        const t = await res.text();
        throw new Error(t || "Failed to fetch uploaded care plans.");
      }

      const data = (await res.json()) as Doc[];
      setDocs(data);
    } catch (e: any) {
      setErr(e?.message || "Failed to load care plans.");
    } finally {
      setLoadingList(false);
    }
  };

  useEffect(() => {
    // Load list on page open
    try {
      if (!localStorage.getItem("access")) {
        setErr("Please login first (no access token found).");
        return;
      }
    } catch {}
    loadCarePlans();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const uploadReal = async () => {
    setErr("");
    if (!file) {
      setErr("Choose a PDF first.");
      return;
    }

    setBusy(true);
    setDone(false);
    setProgress(0);

    // fake progress ticker while upload happens (since fetch doesn't give upload progress)
    let tick = 0;
    const timer = setInterval(() => {
      tick += Math.floor(Math.random() * 8 + 5);
      setProgress((p) => Math.min(92, Math.max(p, tick)));
    }, 220);

    try {
      const fd = new FormData();
      fd.append("doc_type", "care_plan");
      fd.append("title", file.name);
      fd.append("file", file);

      const res = await fetch(`${API}/documents/`, {
        method: "POST",
        headers: authHeadersBearerOnly(),
        body: fd,
      });

      if (!res.ok) {
        const t = await res.text();
        throw new Error(t || "Upload failed.");
      }

      clearInterval(timer);
      setProgress(100);
      setDone(true);
      setFile(null);

      await loadCarePlans();
    } catch (e: any) {
      clearInterval(timer);
      setProgress(0);
      setDone(false);
      setErr(e?.message || "Upload failed.");
    } finally {
      setBusy(false);
    }
  };

  const deleteDoc = async (id: number) => {
    if (!confirm("Delete this uploaded care plan?")) return;
    setErr("");
    try {
      const res = await fetch(`${API}/documents/${id}/`, {
        method: "DELETE",
        headers: authHeadersBearerOnly(),
      });

      if (!res.ok) {
        const t = await res.text();
        throw new Error(t || "Delete failed.");
      }

      setDocs((prev) => prev.filter((d) => d.id !== id));
    } catch (e: any) {
      setErr(e?.message || "Delete failed.");
    }
  };

  // ---- Theme-aware page background like your other pages ----
  const pageBg = useMemo(() => {
    const p = theme.palette.primary.main;
    const s = theme.palette.secondary.main;
    const ok = theme.palette.success.main;

    if (isDark) {
      return (
        `radial-gradient(1200px 700px at 15% 0%, ${alpha(p, 0.22)}, transparent 60%),` +
        `radial-gradient(1000px 600px at 85% 15%, ${alpha(s, 0.20)}, transparent 55%),` +
        `radial-gradient(900px 520px at 50% 110%, ${alpha(ok, 0.12)}, transparent 55%),` +
        `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
      );
    }

    return (
      `radial-gradient(1100px 560px at 12% 0%, ${alpha(p, 0.12)}, transparent 60%),` +
      `radial-gradient(900px 520px at 90% 10%, ${alpha(s, 0.10)}, transparent 60%),` +
      `linear-gradient(180deg, ${theme.palette.background.default} 0%, ${theme.palette.background.default} 100%)`
    );
  }, [theme, isDark]);

  const border = `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.10)}`;

  // ---- Glass card surface ----
  const cardBg = useMemo(() => {
    const glow = isDark
      ? `
        radial-gradient(900px 420px at 12% 10%, ${alpha(theme.palette.primary.main, 0.20)}, transparent 60%),
        radial-gradient(820px 380px at 90% 0%, ${alpha(theme.palette.secondary.main, 0.18)}, transparent 58%),
        radial-gradient(760px 360px at 50% 110%, ${alpha(theme.palette.success.main, 0.12)}, transparent 60%)
      `
      : `
        radial-gradient(900px 420px at 12% 10%, ${alpha(theme.palette.primary.main, 0.12)}, transparent 62%),
        radial-gradient(820px 380px at 90% 0%, ${alpha(theme.palette.secondary.main, 0.10)}, transparent 60%)
      `;

    const base = isDark
      ? `linear-gradient(180deg, ${alpha(theme.palette.background.paper, 0.22)}, ${alpha(
          theme.palette.background.paper,
          0.12
        )})`
      : `linear-gradient(180deg, ${alpha("#ffffff", 0.92)}, ${alpha("#ffffff", 0.72)})`;

    return `${glow}, ${base}`;
  }, [theme, isDark]);

  const shadow = isDark ? "0 30px 95px rgba(0,0,0,0.55)" : "0 22px 70px rgba(2,6,23,0.10)";

  return (
    <Box
      sx={{
        px: { xs: 2, md: 3 },
        py: { xs: 2, md: 3 },
        minHeight: "calc(100vh - 64px)",
        background: pageBg,
      }}
    >
      <Stack spacing={2.2}>
        <Box>
          <Typography variant="h4" sx={{ fontWeight: 950, color: theme.palette.text.primary }}>
            Upload Care Plan
          </Typography>
          <Typography color="text.secondary" sx={{ mt: 0.4 }}>
            Upload a PDF care plan so recommendations can align with provider guidance (only with your consent).
          </Typography>
        </Box>

        {err && (
          <Alert
            severity="error"
            sx={{
              borderRadius: 3,
              border: `1px solid ${alpha(theme.palette.error.main, isDark ? 0.35 : 0.25)}`,
              background: alpha(theme.palette.error.main, isDark ? 0.10 : 0.08),
            }}
          >
            {err}
          </Alert>
        )}

        <Card
          sx={{
            borderRadius: 7,
            overflow: "hidden",
            border,
            boxShadow: shadow,
            background: cardBg,
            backdropFilter: "blur(14px)",
          }}
        >
          {/* Top accent bar like screenshot */}
          <Box
            sx={{
              height: 6,
              background: `linear-gradient(90deg, ${theme.palette.primary.main}, ${theme.palette.secondary.main})`,
            }}
          />

          <CardContent sx={{ p: { xs: 2.2, md: 3 } }}>
            <Stack direction="row" spacing={1.2} alignItems="center" sx={{ mb: 1.2 }}>
              <Box
                sx={{
                  width: 44,
                  height: 44,
                  borderRadius: 3,
                  display: "grid",
                  placeItems: "center",
                  border,
                  background: `linear-gradient(135deg, ${alpha(theme.palette.primary.main, 0.16)}, ${alpha(
                    theme.palette.secondary.main,
                    0.14
                  )})`,
                  color: theme.palette.text.primary,
                }}
              >
                <DescriptionRoundedIcon />
              </Box>

              <Box sx={{ flex: 1, minWidth: 0 }}>
                <Typography sx={{ fontWeight: 950, lineHeight: 1.1 }}>
                  Care Plan PDF
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Supported: PDF • Max: 10MB
                </Typography>
              </Box>

              <Chip
                size="small"
                icon={<AutoAwesomeRoundedIcon />}
                label="AI-aligned guidance"
                sx={{
                  borderRadius: 999,
                  fontWeight: 900,
                  background: `linear-gradient(90deg, ${alpha(theme.palette.primary.main, 0.14)}, ${alpha(
                    theme.palette.secondary.main,
                    0.12
                  )})`,
                  border,
                  color: theme.palette.text.primary,
                }}
              />
            </Stack>

            <Divider sx={{ my: 1.8, opacity: isDark ? 0.16 : 0.26 }} />

            <input
              ref={inputRef}
              type="file"
              accept="application/pdf"
              hidden
              onChange={(e) => onSelect(e.target.files?.[0])}
            />

            {/* Dropzone (theme-aware) */}
            <Stack
              sx={{
                borderRadius: 7,
                border: `1px dashed ${alpha(theme.palette.text.primary, isDark ? 0.35 : 0.28)}`,
                background: isDark ? alpha(theme.palette.background.paper, 0.16) : alpha("#ffffff", 0.60),
                p: { xs: 2.2, md: 3.0 },
                minHeight: { xs: 190, md: 210 },
                justifyContent: "center",
              }}
              spacing={1.2}
              alignItems="center"
            >
              <UploadFileRoundedIcon fontSize="large" />
              <Typography sx={{ fontWeight: 900 }}>Drop your PDF here</Typography>
              <Typography variant="body2" color="text.secondary" align="center">
                Or pick a file manually. We’ll extract structure later (titles, schedules, restrictions).
              </Typography>

              <Stack direction="row" spacing={1.2} sx={{ mt: 1 }} flexWrap="wrap" justifyContent="center">
                <Button
                  variant="outlined"
                  onClick={pick}
                  sx={{
                    borderRadius: 999,
                    fontWeight: 950,
                    px: 2.4,
                    borderColor: alpha(theme.palette.text.primary, isDark ? 0.26 : 0.18),
                    "&:hover": {
                      borderColor: alpha(theme.palette.text.primary, isDark ? 0.42 : 0.26),
                      background: alpha(theme.palette.text.primary, isDark ? 0.06 : 0.04),
                    },
                  }}
                >
                  Choose file
                </Button>

                <Button
                  variant="contained"
                  color="success"
                  onClick={uploadReal}
                  disabled={!file || busy}
                  sx={{
                    borderRadius: 999,
                    fontWeight: 950,
                    px: 2.4,
                    boxShadow: isDark
                      ? "0 16px 44px rgba(34,197,94,0.22)"
                      : "0 14px 36px rgba(34,197,94,0.18)",
                  }}
                >
                  {busy ? "Uploading..." : "Upload"}
                </Button>
              </Stack>

              {meta && (
                <Typography variant="caption" color="text.secondary">
                  Selected: <b>{meta.name}</b> • {meta.mb} MB
                </Typography>
              )}
            </Stack>

            {/* Progress */}
            <Box sx={{ mt: 2 }}>
              <LinearProgress
                variant="determinate"
                value={progress}
                sx={{
                  height: 12,
                  borderRadius: 999,
                  backgroundColor: alpha(theme.palette.text.primary, isDark ? 0.10 : 0.08),
                  "& .MuiLinearProgress-bar": {
                    borderRadius: 999,
                    background: `linear-gradient(90deg, ${theme.palette.primary.main}, ${theme.palette.secondary.main})`,
                  },
                }}
              />
            </Box>

            {/* Note / Done */}
            <Box sx={{ mt: 2 }}>
              {!done ? (
                <Alert
                  severity="info"
                  sx={{
                    borderRadius: 999,
                    background: alpha(theme.palette.primary.main, isDark ? 0.10 : 0.08),
                    border,
                    color: theme.palette.text.primary,
                  }}
                >
                  Your care plan is used only if you consent to Care Plan data. You stay in control.
                </Alert>
              ) : (
                <Alert
                  icon={<CheckCircleRoundedIcon />}
                  severity="success"
                  sx={{
                    borderRadius: 999,
                    background: alpha(theme.palette.success.main, isDark ? 0.12 : 0.10),
                    border,
                    color: theme.palette.text.primary,
                  }}
                >
                  Uploaded successfully. Next: we’ll parse it and align recommendations to your plan.
                </Alert>
              )}
            </Box>

            {/* Uploaded list */}
            <Divider sx={{ my: 2.2, opacity: isDark ? 0.16 : 0.26 }} />

            <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 1 }}>
              <Typography sx={{ fontWeight: 950 }}>Uploaded care plans</Typography>
              <Button
                onClick={loadCarePlans}
                disabled={loadingList}
                variant="outlined"
                sx={{
                  borderRadius: 999,
                  fontWeight: 950,
                  borderColor: alpha(theme.palette.text.primary, isDark ? 0.26 : 0.18),
                  color: theme.palette.text.primary,
                }}
              >
                {loadingList ? "Loading..." : "Refresh"}
              </Button>
            </Stack>

            {docs.length === 0 ? (
              <Alert
                severity="warning"
                sx={{
                  borderRadius: 3,
                  border: `1px solid ${alpha(theme.palette.warning.main, isDark ? 0.35 : 0.25)}`,
                  background: alpha(theme.palette.warning.main, isDark ? 0.10 : 0.08),
                }}
              >
                No care plan uploaded yet.
              </Alert>
            ) : (
              <List
                dense
                sx={{
                  borderRadius: 4,
                  border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.10)}`,
                  background: isDark ? alpha(theme.palette.background.paper, 0.12) : alpha("#ffffff", 0.55),
                }}
              >
                {docs.map((d) => (
                  <ListItem
                    key={d.id}
                    secondaryAction={
                      <Stack direction="row" spacing={0.6}>
                        {d.file_url && (
                          <Tooltip title="Open">
                            <IconButton
                              onClick={() => window.open(d.file_url!, "_blank")}
                              sx={{ color: theme.palette.text.primary }}
                            >
                              <OpenInNewRoundedIcon />
                            </IconButton>
                          </Tooltip>
                        )}

                        <Tooltip title="Delete">
                          <IconButton
                            onClick={() => deleteDoc(d.id)}
                            sx={{ color: alpha(theme.palette.error.main, isDark ? 0.95 : 0.85) }}
                          >
                            <DeleteOutlineRoundedIcon />
                          </IconButton>
                        </Tooltip>
                      </Stack>
                    }
                  >
                    <PictureAsPdfRoundedIcon sx={{ mr: 1 }} />
                    <ListItemText
                      primary={
                        <Typography sx={{ fontWeight: 900 }} noWrap>
                          {d.title || d.file?.split("/").pop() || "Care plan PDF"}
                        </Typography>
                      }
                      secondary={
                        <Typography variant="caption" color="text.secondary">
                          Uploaded: {new Date(d.uploaded_at).toLocaleString()}
                        </Typography>
                      }
                    />
                  </ListItem>
                ))}
              </List>
            )}
          </CardContent>
        </Card>
      </Stack>
    </Box>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import Link from "next/link";
import { alpha, useTheme } from "@mui/material/styles";

import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  Divider,
  LinearProgress,
  List,
  ListItem,
  ListItemText,
  Stack,
  Typography,
  IconButton,
  Tooltip,
} from "@mui/material";

import UploadFileIcon from "@mui/icons-material/UploadFile";
import PictureAsPdfIcon from "@mui/icons-material/PictureAsPdf";
import DeleteOutlineIcon from "@mui/icons-material/DeleteOutline";
import CheckCircleIcon from "@mui/icons-material/CheckCircle";
import LockIcon from "@mui/icons-material/Lock";
import InsightsIcon from "@mui/icons-material/Insights";
import ScienceIcon from "@mui/icons-material/Science";
import ArrowForwardIcon from "@mui/icons-material/ArrowForward";
import OpenInNewRoundedIcon from "@mui/icons-material/OpenInNewRounded";

import { apiFetch } from "@/lib/api"; // ✅ uses JWT + refresh + FormData-safe apiFetch

type UploadState = "idle" | "uploading" | "done";

type Doc = {
  id: number;
  doc_type: "care_plan" | "lab_result";
  title?: string;
  file: string;
  file_url?: string | null;
  uploaded_at: string;
};

type BackendConsent = {
  care_plan_allowed: boolean;
  lab_results_allowed: boolean;
  vitals_allowed: boolean;
  ai_insights_allowed: boolean;
  recommendations_allowed: boolean;
  updated_at?: string;
};

function formatBytes(bytes: number) {
  if (!bytes) return "0 B";
  const k = 1024;
  const sizes = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  const val = bytes / Math.pow(k, i);
  return `${val.toFixed(val >= 10 || i === 0 ? 0 : 1)} ${sizes[i]}`;
}

export default function UploadLabResultsPage() {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";
  const inputRef = useRef<HTMLInputElement | null>(null);

  const [checkingConsent, setCheckingConsent] = useState(true);
  const [labAllowed, setLabAllowed] = useState(false);

  const [dragOver, setDragOver] = useState(false);
  const [files, setFiles] = useState<File[]>([]);
  const [state, setState] = useState<UploadState>("idle");
  const [progress, setProgress] = useState(0);

  const [err, setErr] = useState("");
  const [uploaded, setUploaded] = useState<Doc[]>([]);
  const [loadingList, setLoadingList] = useState(false);

  const locked = useMemo(() => !labAllowed, [labAllowed]);
  const totalSize = useMemo(() => files.reduce((a, f) => a + f.size, 0), [files]);

  const acceptFiles = (incoming: FileList | null) => {
    setErr("");
    if (!incoming || incoming.length === 0) return;

    if (locked) {
      setErr("Lab Results consent is disabled. Enable it to upload PDFs.");
      return;
    }

    const picked = Array.from(incoming);
    const pdfOnly = picked.filter(
      (f) => f.type === "application/pdf" || f.name.toLowerCase().endsWith(".pdf")
    );

    if (pdfOnly.length === 0) {
      setErr("Please upload PDF lab reports only.");
      return;
    }

    // max 5 files
    const merged = [...files, ...pdfOnly].slice(0, 5);

    // enforce 10MB each (demo)
    const tooBig = merged.find((f) => f.size > 10 * 1024 * 1024);
    if (tooBig) {
      setErr(`"${tooBig.name}" exceeds 10MB (demo). Please choose a smaller PDF.`);
      return;
    }

    setFiles(merged);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    acceptFiles(e.dataTransfer.files);
  };

  const removeFile = (idx: number) => {
    setFiles((prev) => prev.filter((_, i) => i !== idx));
  };

  const reset = () => {
    setErr("");
    setFiles([]);
    setState("idle");
    setProgress(0);
  };

  const loadConsent = async () => {
    setCheckingConsent(true);
    setErr("");

    try {
      const c = await apiFetch<BackendConsent>("/consent/", { method: "GET" });
      setLabAllowed(Boolean(c.lab_results_allowed));
    } catch (e: any) {
      setLabAllowed(false);
      setErr(
        typeof e?.message === "string"
          ? e.message
          : "Could not verify consent. Please login and try again."
      );
    } finally {
      setCheckingConsent(false);
    }
  };

  const loadUploadedLabs = async () => {
    setLoadingList(true);
    setErr("");

    try {
      // This endpoint is already consent-gated on backend:
      // GET /documents/?type=lab_result -> 403 if consent disabled
      const data = await apiFetch<Doc[]>("/documents/?type=lab_result", { method: "GET" });
      setUploaded(data);
    } catch (e: any) {
      const msg =
        typeof e?.message === "string" ? e.message : "Failed to load lab reports.";
      setErr(msg);
      setUploaded([]);
    } finally {
      setLoadingList(false);
    }
  };

  useEffect(() => {
    (async () => {
      await loadConsent();
      // load list even if locked: backend may 403, we handle that nicely
      await loadUploadedLabs();
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const uploadAll = async () => {
    setErr("");

    if (locked) {
      setErr("Lab Results consent is disabled. Enable it to upload PDFs.");
      return;
    }

    if (files.length === 0) {
      setErr("Add at least one PDF to upload.");
      return;
    }

    setState("uploading");
    setProgress(0);

    // fake progress ticker (UI only)
    let tick = 0;
    const timer = setInterval(() => {
      tick += Math.floor(Math.random() * 10 + 6);
      setProgress((p) => Math.min(92, Math.max(p, tick)));
    }, 260);

    try {
      for (let i = 0; i < files.length; i++) {
        const f = files[i];

        const fd = new FormData();
        fd.append("doc_type", "lab_result"); // ✅ IMPORTANT: backend requires this
        fd.append("title", f.name);
        fd.append("file", f);

        await apiFetch("/documents/", {
          method: "POST",
          body: fd, // ✅ apiFetch must not force JSON headers here (your comment says it’s FormData-safe)
        });

        setProgress((p) => Math.min(92, p + Math.floor(60 / files.length)));
      }

      clearInterval(timer);
      setProgress(100);
      setState("done");
      setFiles([]);
      await loadUploadedLabs();
    } catch (e: any) {
      clearInterval(timer);
      setProgress(0);
      setState("idle");

      const msg =
        typeof e?.message === "string" ? e.message : "Upload failed.";
      setErr(msg);
    }
  };

  const deleteDoc = async (id: number) => {
    if (!confirm("Delete this lab report PDF?")) return;

    setErr("");
    try {
      await apiFetch(`/documents/${id}/`, { method: "DELETE" });
      setUploaded((prev) => prev.filter((d) => d.id !== id));
    } catch (e: any) {
      setErr(typeof e?.message === "string" ? e.message : "Delete failed.");
    }
  };

  const glassCard = useMemo(
    () => ({
      borderRadius: 5,
      overflow: "hidden",
      border: `1px solid ${alpha(theme.palette.text.primary, isDark ? 0.14 : 0.10)}`,
      background: isDark
        ? `linear-gradient(180deg, ${alpha(theme.palette.background.paper, 0.20)}, ${alpha(
            theme.palette.background.paper,
            0.10
          )})`
        : "linear-gradient(180deg, rgba(20,184,166,0.10), rgba(14,165,233,0.06) 55%, rgba(255,255,255,0.60))",
      backdropFilter: "blur(12px)",
      boxShadow: isDark ? "0 22px 70px rgba(0,0,0,0.45)" : "0 20px 50px rgba(2,8,23,0.06)",
    }),
    [theme, isDark]
  );

  return (
    <Box sx={{ maxWidth: 1200, mx: "auto", p: { xs: 2, md: 3 } }}>
      {/* Header */}
