"use client";

import Link from "next/link";
import { useContext, useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { alpha, useTheme } from "@mui/material/styles";
import { ThemeCtx, ThemeName } from "@/app/providers";

import {
  Avatar,
  Box,
  Button,
  Chip,
  Menu,
  MenuItem,
  Select,
  Typography,
  Tooltip,
  IconButton,
  Divider,
} from "@mui/material";
import { Logout } from "@mui/icons-material";
import { getStoredUsername, isLoggedIn, logout } from "@/lib/api";

function initialsFromName(name: string) {
  const clean = (name || "").trim();
  if (!clean) return "U";
  const parts = clean.split(" ").filter(Boolean);
  const a = parts[0]?.[0] || "U";
  const b = parts[1]?.[0] || "";
  return (a + b).toUpperCase();
}

export default function TopNav() {
  const router = useRouter();
  const muiTheme = useTheme();
  const isDark = muiTheme.palette.mode === "dark";

  const { themeName, setThemeName } = useContext(ThemeCtx);

  const [mounted, setMounted] = useState(false);
  const [logged, setLogged] = useState(false);
  const [username, setUsername] = useState("");
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);

  useEffect(() => {
    setMounted(true);

    const sync = () => {
      const isAuth = isLoggedIn();
      setLogged(isAuth);
      setUsername(isAuth ? getStoredUsername() : "");
    };

    sync();

    const onAuthChanged = () => sync();
    window.addEventListener("praxia-auth-changed", onAuthChanged);
    window.addEventListener("storage", onAuthChanged);

    return () => {
      window.removeEventListener("praxia-auth-changed", onAuthChanged);
      window.removeEventListener("storage", onAuthChanged);
    };
  }, []);

  const avatarText = useMemo(() => initialsFromName(username), [username]);
  const open = Boolean(anchorEl);

  const onLogout = () => {
    logout();
    setAnchorEl(null);
    router.push("/login");
  };

  const shellSx = {
    position: "relative" as const,
    zIndex: 10,
    px: { xs: 2, md: 5 },
    py: 3, // slightly taller
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    background: "transparent",
    borderBottom: "1px solid rgba(0,0,0,0.05)"
  };

  if (!mounted) {
    return (
      <Box sx={shellSx}>
        <Box sx={{ display: "flex", gap: 3 }} />
      </Box>
    );
  }

  return (
    <Box sx={shellSx}>
      {/* MetaboOne Orange Logo + Top Links */}
      <Box sx={{ display: "flex", alignItems: "center", gap: 3 }}>
        <Box
          sx={{
            display: "flex",
            alignItems: "center",
            background: "#ffffff",
            borderRadius: "50%",
            width: 32,
            height: 32,
            boxShadow: "0 2px 6px rgba(0,0,0,0.1)",
            justifyContent: "center",
          }}
        >
          {/* A tiny placeholder for the orange fruit logo */}
          <Typography sx={{ fontSize: 16 }}>🍊</Typography>
        </Box>

        <Typography sx={{ fontWeight: 600, fontSize: 14, color: "#163a5f" }}>Home</Typography>
        <Typography sx={{ fontWeight: 600, fontSize: 14, color: "#1d9ebf" }}>Dashboard</Typography>
        <Typography sx={{ fontWeight: 600, fontSize: 14, color: "#163a5f", opacity: 0.7 }}>Reports</Typography>
        <Typography sx={{ fontWeight: 600, fontSize: 14, color: "#163a5f", opacity: 0.7 }}>Insights</Typography>
      </Box>

      {/* Profile & Icons */}
      <Box sx={{ display: "flex", alignItems: "center", gap: 2 }}>
        <Typography sx={{ fontSize: 18, color: "rgba(0,0,0,0.3)" }}>🔔</Typography>
        <Typography sx={{ fontSize: 18, color: "rgba(0,0,0,0.3)" }}>⚙️</Typography>
        <Typography sx={{ fontSize: 18, color: "rgba(0,0,0,0.3)" }}>💬</Typography>

        {!logged ? (
          <Button
            variant="outlined"
            size="small"
            sx={{ fontWeight: 700, borderRadius: 8, ml: 2 }}
            component={Link}
            href="/login"
          >
            Log In
          </Button>
        ) : (
          <>
            <Tooltip title={username ? `Signed in as ${username}` : "Account"}>
              <IconButton onClick={(e) => setAnchorEl(e.currentTarget)} sx={{ ml: 1, p: 0 }}>
                <Avatar sx={{ width: 34, height: 34, fontWeight: 900, background: "#1d9ebf" }}>
                  {avatarText}
                </Avatar>
              </IconButton>
            </Tooltip>

            <Menu
              anchorEl={anchorEl}
              open={open}
              onClose={() => setAnchorEl(null)}
              transformOrigin={{ horizontal: "right", vertical: "top" }}
              anchorOrigin={{ horizontal: "right", vertical: "bottom" }}
            >
              <MenuItem disabled sx={{ fontWeight: 800, opacity: 0.9 }}>
                {username || "User"}
              </MenuItem>
              <Divider />
              <MenuItem onClick={onLogout} sx={{ fontWeight: 900 }}>
                <Logout sx={{ fontSize: 18, mr: 1 }} />
                Logout
              </MenuItem>
            </Menu>
          </>
        )}
      </Box>
    </Box>
  );
}

/**
 * React hooks for Praxia5Chronic frontend
 */

'use client';

import { useState, useCallback, useEffect } from 'react';
import type { ChronicDisease, LoadingState, APIError } from '@/types';

// ==================== GENERIC HOOKS ====================

/**
 * useAsync - Generic hook for async operations
 */
export function useAsync<T>(
  fn: () => Promise<T>,
  deps?: React.DependencyList
) {
  const [state, setState] = useState<LoadingState & { data?: T }>({
    isLoading: true,
    error: null,
    isSuccess: false,
  });

  useEffect(() => {
    let isMounted = true;

    const runAsync = async () => {
      try {
        setState({ isLoading: true, error: null, isSuccess: false });
        const data = await fn();
        if (isMounted) {
          setState({
            isLoading: false,
            error: null,
            isSuccess: true,
            data,
          });
        }
      } catch (error) {
        if (isMounted) {
          setState({
            isLoading: false,
            error: error instanceof Error ? error : new Error('Unknown error'),
            isSuccess: false,
          });
        }
      }
    };

    runAsync();

    return () => {
      isMounted = false;
    };
  }, deps);

  return state;
}

/**
 * useMutation - Hook for handling POST/PATCH/DELETE operations
 */
export function useMutation<T, D = any>(
  fn: (data: D) => Promise<T>
) {
  const [state, setState] = useState<LoadingState & { data?: T }>({
    isLoading: false,
    error: null,
    isSuccess: false,
  });

  const mutate = useCallback(
    async (data: D) => {
      try {
        setState({ isLoading: true, error: null, isSuccess: false });
        const result = await fn(data);
        setState({
          isLoading: false,
          error: null,
          isSuccess: true,
          data: result,
        });
        return result;
      } catch (error) {
        const errorObj = error instanceof Error ? error : new Error('Unknown error');
        setState({
          isLoading: false,
          error: errorObj,
          isSuccess: false,
        });
        throw errorObj;
      }
    },
    [fn]
  );

  return { ...state, mutate };
}

// ==================== DISEASE HOOKS ====================

/**
 * useDiseases - Fetch all user diseases
 */
export function useDiseases() {
  const [diseases, setDiseases] = useState<ChronicDisease[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    const fetchDiseases = async () => {
      try {
        const response = await fetch('/api/chronic/diseases/', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });

        if (!response.ok) throw new Error('Failed to fetch diseases');

        const data = await response.json();
        setDiseases(data);
      } catch (err) {
        setError(err instanceof Error ? err : new Error('Unknown error'));
      } finally {
        setIsLoading(false);
      }
    };

    fetchDiseases();
  }, []);

  return { diseases, isLoading, error };
}

/**
 * useDisease - Fetch single disease with all relations
 */
export function useDisease(id?: number) {
  const [disease, setDisease] = useState<ChronicDisease | null>(null);
  const [isLoading, setIsLoading] = useState(!!id);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    if (!id) return;

    const fetchDisease = async () => {
      try {
        const response = await fetch(`/api/chronic/diseases/${id}/`, {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });

        if (!response.ok) throw new Error('Failed to fetch disease');

        const data = await response.json();
        setDisease(data);
      } catch (err) {
        setError(err instanceof Error ? err : new Error('Unknown error'));
      } finally {
        setIsLoading(false);
      }
    };

    fetchDisease();
  }, [id]);

  return { disease, isLoading, error };
}

/**
 * useCreateDisease - Create new disease
 */
export function useCreateDisease() {
  return useMutation(async (data) => {
    const response = await fetch('/api/chronic/diseases/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
      },
      body: JSON.stringify(data),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.detail || 'Failed to create disease');
    }

    return response.json();
  });
}

/**
 * useUpdateDisease - Update existing disease
 */
export function useUpdateDisease(id?: number) {
  return useMutation(async (data) => {
    if (!id) throw new Error('Disease ID is required');

    const response = await fetch(`/api/chronic/diseases/${id}/`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
      },
      body: JSON.stringify(data),
    });

    if (!response.ok) throw new Error('Failed to update disease');

    return response.json();
  });
}

// ==================== WEARABLE HOOKS ====================

/**
 * useWearableDevices - Fetch paired wearable devices
 */
export function useWearableDevices() {
  const [devices, setDevices] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    const fetchDevices = async () => {
      try {
        const response = await fetch('/api/data-sources/devices/', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });

        if (!response.ok) throw new Error('Failed to fetch devices');

        const data = await response.json();
        setDevices(data);
      } catch (err) {
        setError(err instanceof Error ? err : new Error('Unknown error'));
      } finally {
        setIsLoading(false);
      }
    };

    fetchDevices();
  }, []);

  return { devices, isLoading, error };
}

/**
 * useHealthMetrics - Fetch health metrics with optional filters
 */
export function useHealthMetrics(filters?: {
  metric_type?: string;
  start_date?: string;
  end_date?: string;
}) {
  const [metrics, setMetrics] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    const fetchMetrics = async () => {
      try {
        const params = new URLSearchParams();
        if (filters?.metric_type) params.append('metric_type', filters.metric_type);
        if (filters?.start_date) params.append('start_date', filters.start_date);
        if (filters?.end_date) params.append('end_date', filters.end_date);

        const query = params.toString();
        const url = `/api/data-sources/metrics/${query ? '?' + query : ''}`;

        const response = await fetch(url, {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });

        if (!response.ok) throw new Error('Failed to fetch metrics');

        const data = await response.json();
        setMetrics(data);
      } catch (err) {
        setError(err instanceof Error ? err : new Error('Unknown error'));
      } finally {
        setIsLoading(false);
      }
    };

    fetchMetrics();
  }, [filters]);

  return { metrics, isLoading, error };
}

// ==================== AI HOOKS ====================

/**
 * useHealthAIQuery - Query health AI (RAG)
 */
export function useHealthAIQuery() {
  const [response, setResponse] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const query = useCallback(async (prompt: string) => {
    try {
      setIsLoading(true);
      setError(null);

      const res = await fetch('/api/ai/query/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
        },
        body: JSON.stringify({ query: prompt }),
      });

      if (!res.ok) throw new Error('Failed to query AI');

      const data = await res.json();
      setResponse(data);
      return data;
    } catch (err) {
      const error = err instanceof Error ? err : new Error('Unknown error');
      setError(error);
      throw error;
    } finally {
      setIsLoading(false);
    }
  }, []);

  return { response, isLoading, error, query };
}

/**
 * useHealthInsights - Fetch AI insights
 */
export function useHealthInsights() {
  const [insights, setInsights] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
