      try {
        const response = await fetch('/api/ai/insights/', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
          },
        });

        if (!response.ok) throw new Error('Failed to fetch insights');

        const data = await response.json();
